"""Error classes for DeepLake Managed Service."""


class ManagedServiceError(Exception):
    """Base exception for all managed service errors."""
    pass


class AuthError(ManagedServiceError):
    """Authentication or authorization failed."""
    pass


class CredentialsError(ManagedServiceError):
    """Failed to retrieve or use database credentials."""
    pass


class IngestError(ManagedServiceError):
    """Data ingestion failed."""
    pass


class TableError(ManagedServiceError):
    """Table operation failed."""
    pass


class TokenError(AuthError):
    """Invalid or expired token."""
    pass


class WorkspaceError(ManagedServiceError):
    """Workspace not found or inaccessible."""
    pass
